from azure.functions import func, QueueMessage
import json
import logging
import pickle


def main(msg: QueueMessage):
    payload = msg.get_body().decode("utf-8")

    obj = None;
    try :
        # Deserialize the string message to an object.
        obj = pickle.loads(payload)

        # Log to trace the deserialization.
        logging.info(f"Deserialized object: {obj}")

    except Exception as ex :
        print(ex);